mapper.select:
SELECT id,plate,username,remark,phone,accident_type accidentType,brand_id brandId,car_ins carIns, chesun_coverage chesunCoverage,car_prices carPrices, accident_time accidentTime,used_prices usedPrices, salvage_prices salvagePrices,cost_upkeep costUpkeep, client_will clientWill
FROM cd_order WHERE 1 = 1
AND state = #{type}
AND (plate LIKE "%"#{text,jdbcType=VARCHAR}"%" or car_ins LIKE "%"#{text,jdbcType=VARCHAR}"%" or brand_id LIKE "%"#{text,jdbcType=VARCHAR}"%")
AND DATE_FORMAT(create_time,'%Y-%m') = #{time}
ORDER by create_time DESC LIMIT #{pagesize},20
